// frontend/src/App.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

// Add this near the top of your App component, after the useState declarations
const API_BASE_URL = 'http://127.0.0.1:8000'; // Use 127.0.0.1 instead of localhost
function App() {
  const [weatherData, setWeatherData] = useState({
    temp_max: 25,
    temp_min: 18,
    temp_avg: 21.5,
    wind_speed: 15,
    humidity: 60,
    city: 'Tunis',
    date: new Date().toISOString().split('T')[0] // Today's date
  });

  const [prediction, setPrediction] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [riskInfo, setRiskInfo] = useState([]);
  const [governorates, setGovernorates] = useState([]);
  const [apiStatus, setApiStatus] = useState('checking');

  // Check API connection on load
  useEffect(() => {
    checkApiConnection();
    fetchRiskInfo();
    fetchGovernorates();
  }, []);

  const checkApiConnection = async () => {
    try {
      const response = await axios.get('http://localhost:8000/health');
      setApiStatus(response.data.model_loaded ? 'connected' : 'no_model');
    } catch (err) {
      setApiStatus('disconnected');
      console.error('API connection error:', err);
    }
  };

  const fetchRiskInfo = async () => {
    try {
      const response = await axios.get('http://localhost:8000/risk-info');
      setRiskInfo(response.data.levels);
    } catch (err) {
      console.error('Error fetching risk info:', err);
    }
  };

  const fetchGovernorates = async () => {
    try {
      const response = await axios.get('http://localhost:8000/governorates');
      setGovernorates(response.data.governorates);
    } catch (err) {
      console.error('Error fetching governorates:', err);
      // Fallback governorates
      setGovernorates(['Tunis', 'Sfax', 'Sousse', 'Bizerte', 'Jendouba']);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setWeatherData(prev => {
      const newData = { ...prev, [name]: value };
      
      // Auto-calculate average if both min and max are present
      if (name === 'temp_max' || name === 'temp_min') {
        const max = parseFloat(name === 'temp_max' ? value : prev.temp_max);
        const min = parseFloat(name === 'temp_min' ? value : prev.temp_min);
        if (!isNaN(max) && !isNaN(min)) {
          newData.temp_avg = ((max + min) / 2).toFixed(1);
        }
      }
      
      return newData;
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    
    try {
      // Convert string values to numbers
      const payload = {
        temp_max: parseFloat(weatherData.temp_max),
        temp_min: parseFloat(weatherData.temp_min),
        temp_avg: parseFloat(weatherData.temp_avg),
        wind_speed: parseFloat(weatherData.wind_speed),
        humidity: parseFloat(weatherData.humidity),
        city: weatherData.city
      };
      
      console.log('Sending payload:', payload);
      
      const response = await axios.post('http://localhost:8000/predict', payload, {
        headers: {
          'Content-Type': 'application/json',
        },
        timeout: 10000 // 10 second timeout
      });
      
      console.log('Received response:', response.data);
      
      // Add date to the prediction
      setPrediction({
        ...response.data,
        forecast_date: weatherData.date
      });
      
    } catch (err) {
      console.error('Full error:', err);
      
      let errorMessage = 'Error making prediction';
      if (err.code === 'ECONNREFUSED') {
        errorMessage = 'Cannot connect to API. Make sure the backend is running on port 8000';
      } else if (err.response) {
        errorMessage = err.response.data?.detail || `Server error: ${err.response.status}`;
      } else if (err.request) {
        errorMessage = 'No response from server. Check if backend is running';
      }
      
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const getRiskColor = (riskLevel) => {
    const colors = {
      'GREEN': '#4CAF50',
      'YELLOW': '#FFC107',
      'ORANGE': '#FF9800',
      'RED': '#F44336',
      'PURPLE': '#9C27B0'
    };
    return colors[riskLevel] || '#999';
  };

  const getRiskEmoji = (riskLevel) => {
    const emojis = {
      'GREEN': '✅',
      'YELLOW': '⚠️',
      'ORANGE': '⚡',
      'RED': '🔴',
      'PURPLE': '🟣'
    };
    return emojis[riskLevel] || '❓';
  };

  return (
    <div className="App">
      <header className="app-header">
        <h1>🌤️ WeatherGuardTN</h1>
        <p>Tunisia Weather Danger & Vigilance Predictor</p>
        
        {/* API Status Indicator */}
        <div className={`api-status ${apiStatus}`}>
          {apiStatus === 'connected' && '✅ Connected to API'}
          {apiStatus === 'checking' && '⏳ Checking API connection...'}
          {apiStatus === 'disconnected' && '❌ API not connected - Start the backend server'}
          {apiStatus === 'no_model' && '⚠️ API connected but model not loaded'}
        </div>
      </header>

      <div className="main-container">
        {/* Risk Legend */}
        <div className="risk-legend">
          <h3>Risk Levels</h3>
          <div className="legend-items">
            {riskInfo.map(risk => (
              <div key={risk.code} className="legend-item">
                <span className="legend-color" style={{ 
                  backgroundColor: risk.color === '🟢' ? '#4CAF50' : 
                                 risk.color === '🟡' ? '#FFC107' :
                                 risk.color === '🟠' ? '#FF9800' :
                                 risk.color === '🔴' ? '#F44336' : '#9C27B0' 
                }}></span>
                <span className="legend-name">{risk.name}</span>
                <span className="legend-desc">{risk.description}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Input Form */}
        <div className="input-section">
          <h2>Weather Forecast</h2>
          <form onSubmit={handleSubmit}>
            {/* Date Selection */}
            <div className="form-group">
              <label>Forecast Date:</label>
              <input
                type="date"
                name="date"
                value={weatherData.date}
                onChange={handleInputChange}
                min={new Date().toISOString().split('T')[0]}
                max={new Date(Date.now() + 7*24*60*60*1000).toISOString().split('T')[0]}
                required
              />
              <small className="field-hint">Select future date for forecast</small>
            </div>

            <div className="form-group">
              <label>City:</label>
              <select 
                name="city" 
                value={weatherData.city} 
                onChange={handleInputChange}
                required
              >
                {governorates.map(city => (
                  <option key={city} value={city}>{city}</option>
                ))}
              </select>
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>Max Temp (°C):</label>
                <input
                  type="number"
                  name="temp_max"
                  value={weatherData.temp_max}
                  onChange={handleInputChange}
                  step="0.1"
                  min="-10"
                  max="50"
                  required
                />
              </div>

              <div className="form-group">
                <label>Min Temp (°C):</label>
                <input
                  type="number"
                  name="temp_min"
                  value={weatherData.temp_min}
                  onChange={handleInputChange}
                  step="0.1"
                  min="-10"
                  max="50"
                  required
                />
              </div>
            </div>

            <div className="form-group">
              <label>Avg Temp (°C):</label>
              <input
                type="number"
                name="temp_avg"
                value={weatherData.temp_avg}
                onChange={handleInputChange}
                step="0.1"
                required
              />
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>Wind Speed (km/h):</label>
                <input
                  type="number"
                  name="wind_speed"
                  value={weatherData.wind_speed}
                  onChange={handleInputChange}
                  step="0.1"
                  min="0"
                  max="200"
                  required
                />
              </div>

              <div className="form-group">
                <label>Humidity (%):</label>
                <input
                  type="number"
                  name="humidity"
                  value={weatherData.humidity}
                  onChange={handleInputChange}
                  step="1"
                  min="0"
                  max="100"
                  required
                />
              </div>
            </div>

            <button type="submit" disabled={loading || apiStatus !== 'connected'} className="predict-btn">
              {loading ? 'Predicting...' : 'Predict Risk for Selected Date'}
            </button>
          </form>
        </div>

        {/* Prediction Result */}
        {prediction && (
          <div className="result-section">
            <h2>Prediction Result for {prediction.forecast_date}</h2>
            <div 
              className="result-card" 
              style={{ backgroundColor: getRiskColor(prediction.risk_level) }}
            >
              <div className="result-header">
                <span className="result-emoji">{getRiskEmoji(prediction.risk_level)}</span>
                <span className="result-risk">{prediction.risk_level}</span>
              </div>
              
              <div className="result-details">
                <div className="weather-details">
                  <h4>Forecast for {prediction.city}:</h4>
                  <p><strong>Date:</strong> {prediction.forecast_date}</p>
                  <p>🌡️ Max: {prediction.weather.temp_max}°C</p>
                  <p>🌡️ Min: {prediction.weather.temp_min}°C</p>
                  <p>🌡️ Avg: {prediction.weather.temp_avg}°C</p>
                  <p>💨 Wind: {prediction.weather.wind_speed} km/h</p>
                  <p>💧 Humidity: {prediction.weather.humidity}%</p>
                  <p><strong>Confidence:</strong> {prediction.confidence}%</p>
                </div>

                <div className="probabilities">
                  <h4>Probability Distribution:</h4>
                  {Object.entries(prediction.probabilities).map(([risk, prob]) => (
                    <div key={risk} className="probability-bar">
                      <span>{risk}</span>
                      <div className="bar-container">
                        <div 
                          className="bar" 
                          style={{ 
                            width: `${prob}%`,
                            backgroundColor: getRiskColor(risk)
                          }}
                        ></div>
                        <span className="bar-value">{prob.toFixed(1)}%</span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {error && (
          <div className="error-message">
            <strong>❌ Error:</strong> {error}
            <div className="error-help">
              <p>Possible solutions:</p>
              <ul>
                <li>Make sure the backend server is running: <code>uvicorn backend.app.api.weather_risk:app --reload --port 8000</code></li>
                <li>Check that port 8000 is not blocked</li>
                <li>Verify the model files exist in mlartifacts/</li>
              </ul>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
